import io
import torch
import torchvision.transforms as transforms
from PIL import Image
from flask import Flask, request, jsonify

app = Flask(__name__)
model = torch.load('your_model.pth', map_location=torch.device('cpu'))
model.eval()
class_names = ['class1', 'class2', 'class3']  # Update with your class names

@app.route('/classify_image', methods=['POST'])
def classify_image():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'})

    image_file = request.files['image']
    image_bytes = image_file.read()
    image = Image.open(io.BytesIO(image_bytes))
    image_tensor = transforms.ToTensor()(image).unsqueeze(0)

    with torch.no_grad():
        outputs = model(image_tensor)
        _, predicted = torch.max(outputs, 1)
        confidence = torch.nn.functional.softmax(outputs, dim=1)[0] * 100

    return jsonify({'predicted_class': class_names[predicted.item()], 'confidence': confidence[predicted.item()].item()})

if __name__ == '__main__':
    app.run()